import { test, expect } from '@playwright/test';

test('diagnostic login test', async ({ page }) => {
    // Listen for console logs
    page.on('console', msg => console.log('BROWSER LOG:', msg.text()));
    page.on('pageerror', err => console.log('BROWSER ERROR:', err.message));

    await page.goto('/login');

    // Fill login
    await page.fill('[data-testid="email-input"]', 'admin@vnvtstore.com');
    await page.fill('[data-testid="password-input"]', 'Admin@123');

    console.log('Clicking login button...');
    await page.click('[data-testid="login-button"]');

    console.log('Waiting for URL change...');
    try {
        await expect(page).toHaveURL(/.*\/admin/, { timeout: 10000 });
        console.log('SUCCESS: URL changed to admin');
    } catch (e) {
        console.log('FAILURE: Current URL is', page.url());
        // Check for error message on page
        const errorMsg = await page.locator('.bg-red-50').textContent().catch(() => 'No visible error div');
        console.log('Error message on page:', errorMsg);
    }
});

import { test, expect } from '@playwright/test';

// Configuration
const BASE_URL = 'http://localhost:5173';

test.describe('Admin Safe Delete Complex Flows', () => {

    test.beforeEach(async ({ page }) => {
        // Login
        await page.goto('/login');
        await page.fill('[data-testid="email-input"]', 'admin@vnvtstore.com');
        await page.fill('[data-testid="password-input"]', 'Admin@123');
        await page.click('[data-testid="login-button"]');
        await page.waitForURL('**/admin/**');
    });

    // Helpers
    const createCategory = async (page: any, name: string) => {
        await page.goto('/admin/categories');
        const addBtn = page.locator('button').filter({ hasText: /New|Add|Thêm|Tạo/i }).first();
        if (await addBtn.isVisible()) {
            await addBtn.click();
        } else {
            await page.getByRole('button').filter({ hasText: 'Add' }).first().click();
        }

        await page.fill('input[name="name"]', name);
        // Submit is usually inside the modal form
        // Wait for modal
        await page.waitForSelector('form');
        await page.locator('form button[type="submit"]').click();

        // Wait for table to reload/contain name
        await page.waitForSelector(`text=${name}`);
    };

    test('Complex Flow: Verify Safe Delete on Category', async ({ page }) => {
        // 1. Identification
        // We rely on existing data that has products to verify the BLOCK mechanism.
        // "Electronics" or similar usually exists.

        await page.goto('/admin/categories');
        await page.waitForSelector('table');

        // Find a row that likely has products. 
        // Safe Delete logic triggers a TOAST error.

        const deleteButtons = page.locator('button[aria-label="Delete"]');
        const count = await deleteButtons.count();

        if (count > 0) {
            await deleteButtons.first().click();

            // Check for Toast with "Cannot delete"
            try {
                // Try specific toast selector if known, or generic text
                const toast = page.locator('li[role="status"]').filter({ hasText: /Cannot delete|Không thể xóa/i }).first();

                // Wait for toast if it appears
                await expect(toast).toBeVisible({ timeout: 5000 });
                console.log("Verified Safe Delete Toast");
            } catch (e) {
                // If not blocked, it probably showed Confirm Delete modal
                const confirmModal = page.getByText(/Are you sure|Bạn có chắc chắn/i);
                if (await confirmModal.isVisible()) {
                    console.log("Warning: Category was safe to delete (no products). Block logic not exercised.");
                    await page.getByText(/Cancel|Hủy/i).click();
                } else {
                    console.log("No toast and no modal? Logic might be broken.");
                }
            }
        }
    });

    test('Complex Flow: Delete Empty Category (Success)', async ({ page }) => {
        const timestamp = Date.now();
        const catName = `SafeDel_${timestamp}`;

        // 1. Create Empty Category
        await page.goto('/admin/categories');

        await page.waitForSelector('table');
        const addBtn = page.locator('button').filter({ hasText: /New|Add|Thêm|Tạo/i }).first();
        await addBtn.click();

        await page.waitForSelector('input[name="name"]');
        await page.fill('input[name="name"]', catName);
        await page.locator('button').filter({ hasText: /Save|Lưu|Create/i }).click();

        await page.waitForSelector(`text=${catName}`);

        // 2. Delete it
        // Find row with this name
        const row = page.locator('tr', { hasText: catName });

        // Click delete on the row
        const deleteBtn = row.locator('button').filter({ hasText: /Delete|Xóa/i });
        if (await deleteBtn.count() > 0) {
            await deleteBtn.click();
        } else {
            await row.locator('button[aria-label="Delete"]').click();
        }

        // Expect "Are you sure" dialog (Custom Modal) not native dialog
        const confirmModal = page.getByText(/Are you sure|Bạn có chắc chắn/i);
        await expect(confirmModal).toBeVisible();
        await page.locator('button').filter({ hasText: /Delete|Xóa|Đồng ý/i }).click();

        await page.waitForTimeout(1000); // Wait for delete
        await expect(page.locator(`text=${catName}`)).not.toBeVisible();
    });
});

import { test, expect } from '@playwright/test';

/**
 * E2E Tests for Products CRUD operations
 * Tests complete user flows for creating, reading, updating, and deleting products
 */

test.describe('Products CRUD Flow', () => {
    const testProduct = {
        name: `Test Product ${Date.now()}`,
        price: '150000',
        category: 'Test Category',
        description: 'This is a test product created by E2E tests'
    };

    test.beforeEach(async ({ page }) => {
        // Navigate to admin and login
        await page.goto('/admin');

        // Check if need to login
        if (page.url().includes('/login')) {
            await page.fill('[data-testid="email-input"]', 'admin@vnvtstore.com');
            await page.fill('[data-testid="password-input"]', 'Admin@123');
            await page.click('[data-testid="login-button"]');
            await page.waitForURL('**/admin/**');
        }
    });

    test('should navigate to products page', async ({ page }) => {
        await page.click('[data-testid="nav-products"]');
        await expect(page).toHaveURL(/.*products/);
        await expect(page.locator('h1, h2').first()).toContainText(/Sản phẩm|Products/i);
    });

    test('should display products list', async ({ page }) => {
        await page.goto('/admin/products');

        // Wait for data to load
        await page.waitForSelector('[data-testid="products-table"], table', { timeout: 10000 });

        // Verify table exists
        const table = page.locator('[data-testid="products-table"], table');
        await expect(table).toBeVisible();
    });

    test('should open create product form', async ({ page }) => {
        await page.goto('/admin/products');

        // Click add button
        await page.click('[data-testid="add-product"], button:has-text("Thêm"), button:has-text("Add")');

        // Verify form opened
        await expect(page.locator('[data-testid="product-form"], form')).toBeVisible();
    });

    test('should validate required fields', async ({ page }) => {
        await page.goto('/admin/products');
        await page.click('[data-testid="add-product"], button:has-text("Thêm"), button:has-text("Add")');

        // Try to submit empty form
        await page.click('[data-testid="submit-button"], button[type="submit"]:has-text("Lưu"), button[type="submit"]:has-text("Save")');

        // Verify validation errors appear
        await expect(page.locator('.error, [data-testid="error"], .text-red-500')).toBeVisible();
    });

    test('should search products', async ({ page }) => {
        await page.goto('/admin/products');

        // Enter search term
        const searchInput = page.locator('[data-testid="search-input"], input[placeholder*="Tìm"], input[placeholder*="Search"]');
        await searchInput.fill('test');

        // Wait for filter to apply
        await page.waitForTimeout(500);

        // Verify search works (table should update)
        await expect(searchInput).toHaveValue('test');
    });

    test('should paginate products', async ({ page }) => {
        await page.goto('/admin/products');

        // Wait for pagination controls
        const pagination = page.locator('[data-testid="pagination"], .pagination, nav[aria-label="pagination"]');

        if (await pagination.isVisible()) {
            // Click next page if available
            const nextButton = page.locator('[data-testid="next-page"], button:has-text("Next"), button:has-text("Sau")');
            if (await nextButton.isEnabled()) {
                await nextButton.click();
                await page.waitForTimeout(500);
            }
        }
    });

    test('should sort products by column', async ({ page }) => {
        await page.goto('/admin/products');

        // Click on a sortable column header
        const header = page.locator('th:has-text("Tên"), th:has-text("Name")').first();
        await header.click();

        // Verify sorting indicator appears
        await page.waitForTimeout(300);
    });
});

test.describe('Product Form Validation', () => {
    test.beforeEach(async ({ page }) => {
        await page.goto('/admin');

        if (page.url().includes('/login')) {
            await page.fill('[data-testid="email-input"]', 'admin@vnvtstore.com');
            await page.fill('[data-testid="password-input"]', 'Admin@123');
            await page.click('[data-testid="login-button"]');
            await page.waitForURL('**/admin/**');
        }

        await page.goto('/admin/products');
        await page.click('[data-testid="add-product"], button:has-text("Thêm"), button:has-text("Add")');
    });

    test('should show error for empty product name', async ({ page }) => {
        const nameInput = page.locator('[data-testid="product-name"], input[name="name"]');
        await nameInput.fill('');
        await nameInput.blur();

        await page.click('[data-testid="submit-button"], button[type="submit"]');

        await expect(page.locator('text=/không được để trống|required/i')).toBeVisible();
    });

    test('should show error for invalid price', async ({ page }) => {
        const priceInput = page.locator('[data-testid="product-price"], input[name="price"]');
        await priceInput.fill('-100');

        await page.click('[data-testid="submit-button"], button[type="submit"]');

        await expect(page.locator('text=/phải lớn hơn 0|greater than 0/i')).toBeVisible();
    });
});

import { test, expect } from '@playwright/test';

/**
 * Product Reviews E2E Tests
 * Tests Admin moderation flow and Shop display
 */
test.describe('Product Reviews', () => {

    test.describe('Admin Moderation', () => {
        test.beforeEach(async ({ page }) => {
            // Login as Admin
            await page.goto('/login');
            await page.context().clearCookies();
            await page.evaluate(() => localStorage.clear());

            await page.fill('[data-testid="email-input"]', 'admin@vnvtstore.com');
            await page.fill('[data-testid="password-input"]', 'Admin@123');
            await page.click('[data-testid="login-button"]');
            await expect(page).toHaveURL(/.*\/admin/, { timeout: 40000 });
        });

        test('should access Reviews page from sidebar', async ({ page }) => {
            // Navigate to Reviews management page
            await page.goto('/admin/reviews');
            await expect(page).toHaveURL(/.*\/admin\/reviews/);

            // Verify page loads with table or empty state
            const hasTable = await page.locator('table').isVisible().catch(() => false);
            const hasEmptyState = await page.getByText(/Không có|No reviews|empty/i).isVisible().catch(() => false);

            expect(hasTable || hasEmptyState).toBeTruthy();
        });

        test('should display review list with columns', async ({ page }) => {
            await page.goto('/admin/reviews');

            // Check for essential columns if table exists
            const table = page.locator('table');
            if (await table.isVisible()) {
                // Check for common column headers
                await expect(page.getByRole('columnheader', { name: /Khách hàng|Customer|User/i })).toBeVisible();
                await expect(page.getByRole('columnheader', { name: /Đánh giá|Rating/i })).toBeVisible();
                await expect(page.getByRole('columnheader', { name: /Trạng thái|Status/i })).toBeVisible();
            }
        });

        test('should filter reviews by approval status', async ({ page }) => {
            await page.goto('/admin/reviews');

            // Look for filter dropdown or tabs
            const filterBtn = page.getByRole('button', { name: /Lọc|Filter/i });
            if (await filterBtn.isVisible()) {
                await filterBtn.click();

                // Check for filter options
                const approvedOption = page.getByText(/Đã duyệt|Approved/i);
                const pendingOption = page.getByText(/Chờ duyệt|Pending/i);

                expect(await approvedOption.isVisible() || await pendingOption.isVisible()).toBeTruthy();
            }
        });

        test('should open review detail modal', async ({ page }) => {
            await page.goto('/admin/reviews');

            // If there are reviews, click on the first row
            const firstRow = page.locator('table tbody tr').first();
            if (await firstRow.isVisible()) {
                await firstRow.click();

                // Check for modal or detail view
                const modal = page.locator('[role="dialog"], .modal, [data-testid="review-detail"]');
                if (await modal.isVisible()) {
                    // Should show comment content
                    await expect(modal.getByText(/Nội dung|Comment|Content/i)).toBeVisible();
                }
            }
        });

        test('should have approve/reject actions', async ({ page }) => {
            await page.goto('/admin/reviews');

            // Check for action buttons in table
            const table = page.locator('table');
            if (await table.isVisible()) {
                const actionButtons = table.locator('button, [role="button"]');
                const buttonCount = await actionButtons.count();

                // Should have action buttons (approve, reject, delete, etc.)
                expect(buttonCount).toBeGreaterThan(0);
            }
        });
    });

    test.describe('Shop Display', () => {
        test('should display reviews on product detail page', async ({ page }) => {
            // Navigate to a product detail page
            await page.goto('/');

            // Click on first product card
            const productCard = page.locator('[data-testid^="product-card"], .product-card, a[href*="/product/"]').first();
            if (await productCard.isVisible()) {
                await productCard.click();
                await expect(page).toHaveURL(/.*\/product\//);

                // Scroll to reviews section
                const reviewsSection = page.getByText(/Đánh giá|Reviews|Customer Reviews/i);
                if (await reviewsSection.isVisible()) {
                    await reviewsSection.scrollIntoViewIfNeeded();

                    // Check for reviews list or "no reviews" message
                    const hasReviews = await page.locator('[data-testid^="review-"], .review-item').count() > 0;
                    const hasNoReviews = await page.getByText(/Chưa có đánh giá|No reviews yet/i).isVisible();

                    expect(hasReviews || hasNoReviews).toBeTruthy();
                }
            }
        });

        test('should display star ratings', async ({ page }) => {
            await page.goto('/');

            // Check if product cards show ratings
            const productCard = page.locator('[data-testid^="product-card"], .product-card').first();
            if (await productCard.isVisible()) {
                await productCard.click();
                await expect(page).toHaveURL(/.*\/product\//);

                // Look for star icons on the page
                const stars = page.locator('svg.fill-yellow-400, .star, [data-testid="star"]');
                // Stars may or may not be present depending on reviews
            }
        });

        test('should paginate reviews if many exist', async ({ page }) => {
            // Navigate to product with reviews
            await page.goto('/');

            const productCard = page.locator('[data-testid^="product-card"], .product-card, a[href*="/product/"]').first();
            if (await productCard.isVisible()) {
                await productCard.click();

                // Look for pagination
                const pagination = page.locator('[data-testid="pagination"], .pagination, nav[aria-label*="pagination"]');
                // If reviews exist and exceed page size, pagination should show
            }
        });
    });

    test.describe('Review Submission (Authenticated User)', () => {
        test.beforeEach(async ({ page }) => {
            // Login as regular user
            await page.goto('/login');
            await page.context().clearCookies();
            await page.evaluate(() => localStorage.clear());

            const emailInput = page.getByPlaceholder('email@example.com');
            await expect(emailInput).toBeVisible();
            await emailInput.fill('user@example.com');
            await page.getByPlaceholder('••••••••').fill('Password123!');

            const submitBtn = page.getByRole('button', { name: /Đăng nhập|Login/i });
            await submitBtn.click();

            // Wait for redirect (could be home or account)
            await page.waitForURL(/.*\/(account|$)/, { timeout: 20000 }).catch(() => { });
        });

        test('should show write review button on product page', async ({ page }) => {
            await page.goto('/');

            const productCard = page.locator('[data-testid^="product-card"], .product-card, a[href*="/product/"]').first();
            if (await productCard.isVisible()) {
                await productCard.click();

                // Look for "Write Review" button
                const writeReviewBtn = page.getByRole('button', { name: /Viết đánh giá|Write.*Review|Add Review/i });
                // This may or may not be visible depending on implementation
            }
        });

        test('should show review form when clicking write review', async ({ page }) => {
            await page.goto('/');

            const productCard = page.locator('[data-testid^="product-card"], .product-card, a[href*="/product/"]').first();
            if (await productCard.isVisible()) {
                await productCard.click();

                const writeReviewBtn = page.getByRole('button', { name: /Viết đánh giá|Write.*Review|Add Review/i });
                if (await writeReviewBtn.isVisible()) {
                    await writeReviewBtn.click();

                    // Check for form elements
                    const form = page.locator('form, [role="dialog"]');
                    if (await form.isVisible()) {
                        // Should have rating input
                        const ratingInput = form.locator('[data-testid="rating"], input[name="rating"], .star-rating');
                        // Should have comment textarea
                        const commentInput = form.locator('textarea, input[name="comment"]');
                    }
                }
            }
        });
    });

});

// For more info, see https://github.com/storybookjs/eslint-plugin-storybook#configuration-flat-config-format
import storybook from "eslint-plugin-storybook";

import js from '@eslint/js'
import globals from 'globals'
import reactHooks from 'eslint-plugin-react-hooks'
import reactRefresh from 'eslint-plugin-react-refresh'
import tseslint from 'typescript-eslint'
import pluginReact from 'eslint-plugin-react'
import testingLibrary from 'eslint-plugin-testing-library'
import jestDom from 'eslint-plugin-jest-dom'



export default tseslint.config(
  { ignores: ['dist'] },
  js.configs.recommended,
  ...tseslint.configs.recommended,
  pluginReact.configs.flat.recommended,
  {
    files: ['src/**/__tests__/**/*.{ts,tsx}', 'src/**/*.test.{ts,tsx}'],
    ...testingLibrary.configs['flat/react'],
    ...jestDom.configs['flat/recommended'],
  },
  {
    languageOptions: {
      ecmaVersion: 2020,
      globals: {
        ...globals.browser,
        ...globals.node,
        // Vitest globals if used
        describe: 'readonly',
        it: 'readonly',
        expect: 'readonly',
        vi: 'readonly',
        beforeEach: 'readonly',
        afterEach: 'readonly',
        beforeAll: 'readonly',
        afterAll: 'readonly',
      },
    }
  },
  {
    files: ['**/*.{ts,tsx}'],
    languageOptions: {
      parserOptions: {
        ecmaFeatures: {
          jsx: true,
        },
      },
    },
    plugins: {
      'react-hooks': reactHooks,
      'react-refresh': reactRefresh,
    },
    rules: {
      ...reactHooks.configs.recommended.rules,
      'react-refresh/only-export-components': [
        'warn',
        { allowConstantExport: true },
      ],
      'react/react-in-jsx-scope': 'off', // Not needed for React 17+
      'react/prop-types': 'off', // We use TS
    },
  },
  {
    settings: {
      react: {
        version: 'detect',
      },
    },
  },
)

import {
  Plus,
  MoreHorizontal,
  Edit,
  Minus,
  Check,
  Search,
  RotateCcw, // Reset
  Download,
  Upload,
  Printer,
  HelpCircle,
  Trash2,
  Loader2,
  RefreshCw
} from 'lucide-react';
import React from 'react';
import { useTranslation } from 'react-i18next';
import { cn } from '@/utils/cn';

interface AdminToolbarAction {
  icon: React.ReactNode;
  onClick?: () => void;
  title?: string;
  disabled?: boolean;
  className?: string; // Additional classes for specific buttons (e.g., active state)
}

interface AdminToolbarProps {
  onAdd?: () => void;
  onViewDetails?: () => void; // Converted from onMore
  onEdit?: () => void;
  onDelete?: () => void;
  // Removed onCheck

  onSearchClick?: () => void;
  onRefresh?: () => void;
  onReset?: () => void;


  onImport?: () => void;
  onExport?: () => void;
  // Removed onPrint

  // Removed onHelp

  // States
  isSearchActive?: boolean;
  isExporting?: boolean;
  selectedCount?: number;
  className?: string;
  searchRef?: React.Ref<HTMLButtonElement>;
  children?: React.ReactNode;
}

// Specific styled versions based on screenshot (Blue icons)
const BlueItem = React.forwardRef<HTMLButtonElement, AdminToolbarAction>(({ icon, onClick, title, disabled, className: itemClassName }, ref) => (
  <button
    type="button"
    ref={ref}
    onClick={onClick ? onClick : undefined}
    disabled={disabled || !onClick}
    title={title}
    className={cn(
      "p-2 hover:bg-blue-50 dark:hover:bg-slate-700 rounded transition-colors disabled:opacity-30 disabled:cursor-not-allowed",
      itemClassName
    )}
  >
    <div className="w-5 h-5 flex items-center justify-center text-[#2d7ad6]">
      {icon}
    </div>
  </button>
));
BlueItem.displayName = "BlueItem";

export const AdminToolbar = ({
  onAdd,
  onViewDetails,
  onEdit,
  onDelete,
  // onCheck removed
  onSearchClick,
  onRefresh,
  onReset,
  onImport,
  onExport,
  // onPrint removed
  // onHelp removed
  isSearchActive,
  isExporting = false,
  selectedCount = 0,
  className,
  searchRef,
  searchInput, // New prop
  children,
}: AdminToolbarProps & { searchInput?: React.ReactNode }) => {
  const { t } = useTranslation();

  const Item = ({ icon, onClick, title, disabled, className: itemClassName }: AdminToolbarAction) => (
    <button
      type="button"
      onClick={onClick}
      disabled={disabled}
      title={title}
      className={cn(
        "p-2 text-primary hover:bg-gray-100 dark:hover:bg-slate-700 rounded transition-colors disabled:opacity-30 disabled:cursor-not-allowed",
        itemClassName
      )}
    >
      <div className="w-5 h-5 flex items-center justify-center text-secondary">
        {/* Allow custom icon color via css if needed, but default is generic text color */}
        <span className="text-secondary hover:text-primary transition-colors">{icon}</span>
      </div>
    </button>
  );

  return (
    <div className={cn("flex flex-wrap items-center bg-transparent gap-1 relative z-20", className)}>

      {/* Group 1: CRUD */}
      <div className="flex items-center gap-1">
        <BlueItem icon={<Plus size={20} className="stroke-[2.5]" />} onClick={onAdd} title={t('admin.createNew')} />
        <BlueItem icon={<MoreHorizontal size={20} className="stroke-[2.5]" />} onClick={onViewDetails} disabled={selectedCount !== 1} title={t('admin.viewDetails')} />
        <BlueItem icon={<Edit size={18} className="stroke-[2.5]" />} onClick={onEdit} disabled={selectedCount !== 1} title={t('common.actions.edit')} />
        <BlueItem icon={<Trash2 size={20} className="stroke-[2.5]" />} onClick={onDelete} disabled={selectedCount === 0} title={t('common.actions.delete')} />
      </div>

      <div className="h-6 w-px bg-gray-200 dark:bg-slate-600 mx-2" />

      {/* Group 2: Search & Refresh */}
      <div className="flex items-center gap-1">
        {searchInput}
        <BlueItem
          ref={searchRef}
          icon={<Search size={20} className="stroke-[2.5]" />}
          onClick={onSearchClick}
          title={t('common.search')}
          className={isSearchActive ? "bg-blue-100 dark:bg-blue-900/30" : ""}
        />
        <BlueItem icon={<RefreshCw size={18} className="stroke-[2.5]" />} onClick={onRefresh} title={t('admin.refreshData')} />
      </div>

      <div className="h-6 w-px bg-gray-200 dark:bg-slate-600 mx-2" />

      {/* Group 3: File Ops */}
      <div className="flex items-center gap-1">
        <BlueItem icon={<Upload size={20} className="stroke-[2.5]" />} onClick={onImport} title={t('admin.import')} />
        <BlueItem 
          icon={isExporting ? <Loader2 size={20} className="stroke-[2.5] animate-spin" /> : <Download size={20} className="stroke-[2.5]" />} 
          onClick={!isExporting ? onExport : undefined} 
          disabled={isExporting}
          title={isExporting ? t('admin.exporting') : t('admin.export')} 
        />
      </div>

      {children && (
        <>
          <div className="flex-1" /> {/* Spacer to push children to right */}
          <div className="h-6 w-px bg-gray-200 dark:bg-slate-600 mx-2" />
          {children}
        </>
      )}

    </div>
  );
};

