import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Search, X } from 'lucide-react';
import { Button, Input, Modal } from '@/components/ui';

export interface FilterDef {
    id: string;
    label: string;
    type: 'text' | 'select' | 'date' | 'number';
    options?: { label: string; value: string }[];
    placeholder?: string;
    className?: string; // For custom width or spanning
}

interface AdvancedFilterProps {
    isOpen: boolean;
    onClose: () => void;
    filterDefs: FilterDef[];
    onApply: (filters: Record<string, string>) => void;
    onClear: () => void;
    currentFilters: Record<string, string>;
}

export const AdvancedFilter = ({
    isOpen,
    onClose,
    filterDefs,
    onApply,
    onClear,
    currentFilters,
}: AdvancedFilterProps) => {
    const { t } = useTranslation();
    const [localFilters, setLocalFilters] = useState<Record<string, string>>(currentFilters);

    useEffect(() => {
        setLocalFilters(currentFilters);
    }, [currentFilters, isOpen]);

    const handleChange = (id: string, value: string) => {
        setLocalFilters((prev) => ({ ...prev, [id]: value }));
    };

    const handleApply = () => {
        onApply(localFilters);
        onClose();
    };

    const handleClear = () => {
        setLocalFilters({});
        onClear();
    };

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            title={null} // Custom header or just clean
            size="xl" // Wider modal for 2 cols
            footer={null} // Custom footer
            className="max-w-4xl"
        >
            <div className="p-1">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-4">
                    {filterDefs.map((field) => (
                        <div key={field.id} className="grid grid-cols-12 items-center gap-2">
                            <label
                                htmlFor={field.id}
                                className="col-span-4 text-right text-sm font-semibold text-blue-600 dark:text-blue-400 pr-2"
                            >
                                {field.label}
                            </label>
                            <div className="col-span-8">
                                {field.type === 'select' ? (
                                    <select
                                        id={field.id}
                                        value={localFilters[field.id] || ''}
                                        onChange={(e) => handleChange(field.id, e.target.value)}
                                        className="w-full px-3 py-2 border rounded-md bg-white dark:bg-slate-800 focus:outline-none focus:ring-1 focus:ring-primary"
                                    >
                                        <option value="">{t('common.choose') || 'Chọn'}</option>
                                        {field.options?.map((opt) => (
                                            <option key={opt.value} value={opt.value}>
                                                {opt.label}
                                            </option>
                                        ))}
                                    </select>
                                ) : field.type === 'date' ? (
                                    <Input
                                        id={field.id}
                                        type="datetime-local"
                                        value={localFilters[field.id] || ''}
                                        onChange={(e) => handleChange(field.id, e.target.value)}
                                        className="w-full"
                                    />
                                ) : (
                                    <Input
                                        id={field.id}
                                        type={field.type === 'number' ? 'number' : 'text'}
                                        value={localFilters[field.id] || ''}
                                        onChange={(e) => handleChange(field.id, e.target.value)}
                                        placeholder={field.placeholder}
                                        className="w-full"
                                    />
                                )}
                            </div>
                        </div>
                    ))}
                </div>

                {/* Footer Actions */}
                <div className="flex justify-center gap-4 mt-8 pb-2">
                    <Button
                        onClick={handleApply}
                        className="bg-green-600 hover:bg-green-700 text-white min-w-[120px]"
                        leftIcon={<Search size={18} />}
                    >
                        {t('common.search') || 'Tìm kiếm'}
                    </Button>
                    <Button
                        variant="outline"
                        onClick={onClose}
                        className="bg-gray-500 hover:bg-gray-600 text-white border-transparent hover:text-white min-w-[100px]"
                        leftIcon={<X size={18} />}
                    >
                        {t('common.close') || 'Đóng'}
                    </Button>
                </div>
            </div>
        </Modal>
    );
};

import { memo } from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Minus, Plus, ShoppingBag, ArrowRight } from 'lucide-react';
import { cn } from '@/utils/cn';
import { Button } from '@/components/ui';
import SharedImage from '@/components/common/Image';
import { useCartStore, useUIStore } from '@/store';
import { formatCurrency } from '@/utils/format';

export const CartDrawer = memo(() => {
  const { t } = useTranslation();
  const { cartOpen, setCartOpen } = useUIStore();
  const { items, removeItem, updateQuantity, getTotal, clearCart } = useCartStore();

  const total = getTotal();

  return (
    <AnimatePresence>
      {cartOpen && (
        <>
          {/* Overlay */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/50 z-[150]"
            onClick={() => setCartOpen(false)}
          />

          {/* Drawer */}
          <motion.div
            initial={{ x: '100%' }}
            animate={{ x: 0 }}
            exit={{ x: '100%' }}
            transition={{ type: 'tween', duration: 0.3 }}
            className="fixed top-0 right-0 bottom-0 w-full max-w-md bg-primary z-[150] flex flex-col shadow-2xl"
          >
            {/* Header */}
            <div className="flex items-center justify-between p-4 border-b">
              <h2 className="text-lg font-bold flex items-center gap-2">
                <ShoppingBag size={20} />
                {t('cart.title')} ({items.length})
              </h2>
              <Button variant="ghost" size="sm" onClick={() => setCartOpen(false)}>
                <X size={24} />
              </Button>
            </div>

            {/* Cart Items */}
            {items.length === 0 ? (
              <div className="flex-1 flex flex-col items-center justify-center text-center p-8">
                <div className="w-24 h-24 bg-secondary rounded-full flex items-center justify-center mb-4">
                  <ShoppingBag size={48} className="text-tertiary" />
                </div>
                <h3 className="text-lg font-semibold text-primary mb-2">{t('cart.empty')}</h3>
                <p className="text-secondary mb-6">{t('cart.emptyMessage')}</p>
                <Button onClick={() => setCartOpen(false)}>
                  {t('cart.continueShopping')}
                </Button>
              </div>
            ) : (
              <div className="flex-1 overflow-y-auto p-4 space-y-4">
                {items.map((item) => (
                  <motion.div
                    key={item.code}
                    layout
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    className="flex gap-4 p-3 bg-secondary rounded-xl"
                  >
                    {/* Image */}
                    <Link
                      to={`/product/${item.product.code}`}
                      onClick={() => setCartOpen(false)}
                      className="flex-shrink-0"
                    >
                      <SharedImage
                        src={item.product.image}
                        alt={item.product.name}
                        className="w-20 h-20 object-cover rounded-lg"
                      />
                    </Link>

                    {/* Info */}
                    <div className="flex-1 min-w-0">
                      <Link
                        to={`/product/${item.product.code}`}
                        onClick={() => setCartOpen(false)}
                        className="font-medium text-primary hover:text-primary-dark transition-colors line-clamp-2"
                      >
                        {item.product.name}
                      </Link>
                      {(item.size || item.color) && (
                        <div className="flex flex-wrap gap-2 mt-1 text-xs text-secondary">
                          {item.size && (
                            <span className="bg-tertiary/20 px-1.5 py-0.5 rounded border">
                              {t('product.size') || 'Size'}: {item.size}
                            </span>
                          )}
                          {item.color && (
                            <span className="bg-tertiary/20 px-1.5 py-0.5 rounded border">
                              {t('product.color') || 'Color'}: {item.color}
                            </span>
                          )}
                        </div>
                      )}
                      <p className="text-error font-bold mt-1">
                        {formatCurrency(item.product.price)}
                      </p>

                      {/* Quantity controls */}
                      <div className="flex items-center justify-between mt-2">
                        <div className="flex items-center border rounded-lg overflow-hidden">
                          <button
                            onClick={() => updateQuantity(item.code, Math.max(1, item.quantity - 1))}
                            className="p-1.5 hover:bg-tertiary transition-colors"
                            disabled={item.quantity <= 1}
                          >
                            <Minus size={14} />
                          </button>
                          <span className="px-3 text-sm font-medium">{item.quantity}</span>
                          <button
                            onClick={() => updateQuantity(item.code, item.quantity + 1)}
                            className="p-1.5 hover:bg-tertiary transition-colors"
                          >
                            <Plus size={14} />
                          </button>
                        </div>

                        <button
                          onClick={() => removeItem(item.code)}
                          className="text-tertiary hover:text-error transition-colors"
                        >
                          <X size={18} />
                        </button>
                      </div>
                    </div>
                  </motion.div>
                ))}
              </div>
            )}

            {/* Footer */}
            {items.length > 0 && (
              <div className="border-t p-4 space-y-4 bg-secondary/50">
                {/* Subtotal */}
                <div className="flex items-center justify-between">
                  <span className="text-secondary">{t('cart.subtotal')}</span>
                  <span className="text-xl font-bold text-primary">{formatCurrency(total)}</span>
                </div>

                {/* Actions */}
                <div className="space-y-2">
                  <Button
                    fullWidth
                    rightIcon={<ArrowRight size={18} />}
                    onClick={() => {
                      setCartOpen(false);
                      window.location.href = '/checkout';
                    }}
                  >
                    {t('cart.checkout')}
                  </Button>
                  <Link
                    to="/cart"
                    onClick={() => setCartOpen(false)}
                    className="block text-center text-sm text-primary hover:underline"
                  >
                    {t('cart.title')}
                  </Link>
                </div>

                {/* Clear cart */}
                <button
                  onClick={clearCart}
                  className="w-full text-center text-xs text-tertiary hover:text-error transition-colors"
                >
                  Xóa tất cả
                </button>
              </div>
            )}
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
});

CartDrawer.displayName = 'CartDrawer';

export default CartDrawer;

import { memo, useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MessageCircle, X, Send, Bot, User, Minimize2 } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { cn } from '@/utils/cn';
import { Button } from '@/components/ui';
import type { ChatMessage } from '@/types';

export const ChatWidget = memo(() => {
  const { t } = useTranslation();
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [message, setMessage] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '1',
      role: 'assistant',
      content: 'Xin chào! 👋 Tôi là trợ lý AI của VNVT Store. Tôi có thể giúp gì cho bạn?',
      timestamp: new Date().toISOString(),
    },
  ]);
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!message.trim()) return;

    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      content: message,
      timestamp: new Date().toISOString(),
    };

    setMessages((prev) => [...prev, userMessage]);
    setMessage('');
    setIsTyping(true);

    // Simulate AI response (replace with actual AI integration)
    setTimeout(() => {
      const responses = [
        'Cảm ơn bạn đã liên hệ! Bạn có thể cho tôi biết thêm về sản phẩm bạn đang tìm kiếm không?',
        'Tôi có thể giúp bạn tìm sản phẩm phù hợp. Bạn đang quan tâm đến danh mục nào?',
        'Chúng tôi hiện đang có nhiều chương trình khuyến mãi hấp dẫn. Bạn có muốn tôi giới thiệu không?',
        'Để hỗ trợ bạn tốt hơn, bạn có thể liên hệ hotline 1900 123 456 hoặc chat Zalo nhé!',
      ];

      const aiMessage: ChatMessage = {
        id: Date.now().toString(),
        role: 'assistant',
        content: responses[Math.floor(Math.random() * responses.length)],
        timestamp: new Date().toISOString(),
      };

      setMessages((prev) => [...prev, aiMessage]);
      setIsTyping(false);
    }, 1500);
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <>
      {/* Chat Button */}
      <motion.button
        className={cn(
          'fixed bottom-6 right-6 z-50 w-14 h-14 rounded-full shadow-lg flex items-center justify-center transition-colors',
          isOpen ? 'bg-gray-600' : 'bg-gradient-to-r from-primary to-purple-500 hover:shadow-xl'
        )}
        onClick={() => setIsOpen(!isOpen)}
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
      >
        {isOpen ? <X size={24} className="text-white" /> : <MessageCircle size={24} className="text-white" />}
      </motion.button>

      {/* Chat Window */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.9 }}
            animate={{ 
              opacity: 1, 
              y: 0, 
              scale: 1,
              height: isMinimized ? 'auto' : 500,
            }}
            exit={{ opacity: 0, y: 20, scale: 0.9 }}
            className="fixed bottom-24 right-6 z-50 w-96 max-w-[calc(100vw-3rem)] bg-primary rounded-2xl shadow-2xl overflow-hidden flex flex-col"
          >
            {/* Header */}
            <div className="bg-gradient-to-r from-primary to-purple-500 text-white p-4 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-white/20 rounded-full flex items-center justify-center">
                  <Bot size={20} />
                </div>
                <div>
                  <h3 className="font-semibold">AI Assistant</h3>
                  <p className="text-xs text-white/80">Online • Phản hồi nhanh</p>
                </div>
              </div>
              <button
                onClick={() => setIsMinimized(!isMinimized)}
                className="p-2 hover:bg-white/20 rounded-lg transition-colors"
              >
                <Minimize2 size={18} />
              </button>
            </div>

            {!isMinimized && (
              <>
                {/* Messages */}
                <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-secondary">
                  {messages.map((msg) => (
                    <div
                      key={msg.id}
                      className={cn('flex gap-3', msg.role === 'user' ? 'flex-row-reverse' : '')}
                    >
                      <div
                        className={cn(
                          'w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0',
                          msg.role === 'user'
                            ? 'bg-primary text-white'
                            : 'bg-gradient-to-r from-primary to-purple-500 text-white'
                        )}
                      >
                        {msg.role === 'user' ? <User size={16} /> : <Bot size={16} />}
                      </div>
                      <div
                        className={cn(
                          'max-w-[75%] px-4 py-2 rounded-2xl',
                          msg.role === 'user'
                            ? 'bg-primary text-white rounded-br-md'
                            : 'bg-primary shadow-sm rounded-bl-md'
                        )}
                      >
                        <p className="text-sm">{msg.content}</p>
                      </div>
                    </div>
                  ))}

                  {/* Typing indicator */}
                  {isTyping && (
                    <div className="flex gap-3">
                      <div className="w-8 h-8 rounded-full bg-gradient-to-r from-primary to-purple-500 flex items-center justify-center">
                        <Bot size={16} className="text-white" />
                      </div>
                      <div className="bg-primary shadow-sm px-4 py-2 rounded-2xl rounded-bl-md">
                        <div className="flex gap-1">
                          <span className="w-2 h-2 bg-tertiary rounded-full animate-bounce" />
                          <span className="w-2 h-2 bg-tertiary rounded-full animate-bounce [animation-delay:0.2s]" />
                          <span className="w-2 h-2 bg-tertiary rounded-full animate-bounce [animation-delay:0.4s]" />
                        </div>
                      </div>
                    </div>
                  )}

                  <div ref={messagesEndRef} />
                </div>

                {/* Input */}
                <div className="p-4 border-t bg-primary">
                  <div className="flex gap-2">
                    <input
                      type="text"
                      value={message}
                      onChange={(e) => setMessage(e.target.value)}
                      onKeyPress={handleKeyPress}
                      placeholder="Nhập tin nhắn..."
                      className="flex-1 px-4 py-2 border rounded-full text-sm focus:outline-none focus:border-primary"
                    />
                    <Button
                      onClick={handleSend}
                      disabled={!message.trim()}
                      rounded
                      size="sm"
                      className="w-10 h-10 p-0"
                    >
                      <Send size={18} />
                    </Button>
                  </div>
                  <p className="text-xs text-tertiary text-center mt-2">
                    Powered by AI • VNVT Store
                  </p>
                </div>
              </>
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
});

ChatWidget.displayName = 'ChatWidget';

