import { useTranslation } from 'react-i18next';
import { useState, useEffect } from 'react';
import { Button, Input, Badge } from '@/components/ui';
import { RefreshCw, X, Plus, Trash2 } from 'lucide-react';

export interface ProductVariantData {
  sku: string;
  attributes: Record<string, string>;
  price: number;
  stockQuantity: number;
}

interface ProductVariantManagerProps {
  initialVariants?: ProductVariantData[];
  basePrice: number;
  productCode?: string;
  onChange: (variants: ProductVariantData[]) => void;
}

interface Attribute {
  name: string;
  values: string[];
}

export const ProductVariantManager = ({
  initialVariants = [],
  basePrice,
  productCode,
  onChange
}: ProductVariantManagerProps) => {
  const { t } = useTranslation();
  const [attributes, setAttributes] = useState<Attribute[]>([]);
  const [variants, setVariants] = useState<ProductVariantData[]>(initialVariants);

  // Parse initial attributes from variants if any
  useEffect(() => {
    if (initialVariants.length > 0 && attributes.length === 0) {
      const attrMap: Record<string, Set<string>> = {};
      initialVariants.forEach(v => {
        const attrs = typeof v.attributes === 'string' ? JSON.parse(v.attributes) : v.attributes;
        Object.entries(attrs).forEach(([name, value]) => {
          if (!attrMap[name]) attrMap[name] = new Set<string>();
          attrMap[name].add(value as string);
        });
      });
      setAttributes(Object.entries(attrMap).map(([name, values]) => ({
        name,
        values: Array.from(values)
      })));
    }
  }, [initialVariants]);

  const addAttribute = () => setAttributes([...attributes, { name: '', values: [] }]);
  
  const updateAttributeName = (idx: number, name: string) => {
    const newAttrs = [...attributes];
    newAttrs[idx].name = name;
    setAttributes(newAttrs);
  };

  const addAttributeValue = (idx: number, value: string) => {
    if (!value.trim()) return;
    const newAttrs = [...attributes];
    if (!newAttrs[idx].values.includes(value)) {
      newAttrs[idx].values.push(value);
      setAttributes(newAttrs);
    }
  };

  const removeAttributeValue = (attrIdx: number, valIdx: number) => {
    const newAttrs = [...attributes];
    newAttrs[attrIdx].values.splice(valIdx, 1);
    setAttributes(newAttrs);
  };

  const removeAttribute = (idx: number) => {
    setAttributes(attributes.filter((_, i) => i !== idx));
  };

  const generateVariants = () => {
    const validAttrs = attributes.filter(a => a.name.trim() && a.values.length > 0);
    if (validAttrs.length === 0) return;

    const combinations = validAttrs.reduce((acc, attr) => {
      const next: Record<string, string>[] = [];
      acc.forEach(prevCombo => {
        attr.values.forEach(val => {
          next.push({ ...prevCombo, [attr.name]: val });
        });
      });
      return next;
    }, [{} as Record<string, string>]);

    const newVariants = combinations.map(combo => {
      const attrStr = Object.values(combo).join('-');
      // Check if variant with these attributes already exists to preserve its data
      const existing = variants.find(v => {
          const vAttrs = typeof v.attributes === 'string' ? JSON.parse(v.attributes) : v.attributes;
          return JSON.stringify(vAttrs) === JSON.stringify(combo);
      });
      
      return existing || {
        sku: `${productCode || 'PROD'}-${attrStr.toUpperCase()}`,
        attributes: combo,
        price: basePrice,
        stockQuantity: 0
      };
    });

    setVariants(newVariants);
    onChange(newVariants);
  };

  const updateVariant = (idx: number, field: keyof ProductVariantData, value: string | number | Record<string, string>) => {
    const newVariants = [...variants];
    newVariants[idx] = { ...newVariants[idx], [field]: value };
    setVariants(newVariants);
    onChange(newVariants);
  };

  return (
    <div className="space-y-6">
      <div className="space-y-4 bg-slate-50 dark:bg-slate-900/50 p-4 rounded-xl border border-border-color">
        <div className="flex justify-between items-center mb-2">
            <h4 className="text-sm font-semibold text-primary">{t('product.variantAttributes')}</h4>
            <Button type="button" size="sm" variant="outline" onClick={addAttribute}>
                <Plus size={14} className="mr-1" /> {t('common.add')}
            </Button>
        </div>
        
        {attributes.length === 0 ? (
            <p className="text-center text-sm text-tertiary py-4 italic">{t('product.noAttributes')}</p>
        ) : (
            attributes.map((attr, idx) => (
                <div key={idx} className="space-y-2 pb-4 border-b border-border-color last:border-0 last:pb-0">
                    <div className="flex gap-2 items-center">
                        <Input 
                            className="flex-1 h-9 text-sm font-medium" 
                            placeholder={t('common.fields.attributeName')}
                            value={attr.name}
                            onChange={(e) => updateAttributeName(idx, e.target.value)}
                        />
                        <button type="button" onClick={() => removeAttribute(idx)} className="text-slate-400 hover:text-red-500">
                            <Trash2 size={16} />
                        </button>
                    </div>
                    <div className="flex flex-wrap gap-2 items-center">
                        {attr.values.map((val, vIdx) => (
                            <Badge key={vIdx} color="primary" className="flex items-center gap-1 pr-1 py-1">
                                {val}
                                <button type="button" onClick={() => removeAttributeValue(idx, vIdx)} className="hover:bg-slate-200/20 rounded-full p-0.5">
                                    <X size={12} />
                                </button>
                            </Badge>
                        ))}
                        <Input 
                            className="w-32 h-7 text-xs" 
                            placeholder={t('common.addValue')}
                            onKeyDown={(e) => {
                                if (e.key === 'Enter') {
                                    e.preventDefault();
                                    addAttributeValue(idx, e.currentTarget.value);
                                    e.currentTarget.value = '';
                                }
                            }}
                        />
                    </div>
                </div>
            ))
        )}

        {attributes.length > 0 && (
            <div className="pt-2 flex justify-center">
                <Button type="button" size="sm" onClick={generateVariants} className="gap-2">
                    <RefreshCw size={14} /> {t('product.generateVariants')}
                </Button>
            </div>
        )}
      </div>

      {variants.length > 0 && (
        <div className="space-y-3">
            <h4 className="text-sm font-semibold text-primary px-1">{t('product.variants')}</h4>
            <div className="bg-white dark:bg-slate-950 rounded-xl border border-border-color overflow-hidden scrollbar-thin overflow-x-auto">
                <table className="w-full text-sm min-w-[600px]">
                    <thead>
                        <tr className="bg-slate-50 dark:bg-slate-900/50 text-secondary text-xs font-semibold border-b border-border-color">
                            <th className="px-4 py-3 text-left">{t('product.variant')}</th>
                            <th className="px-4 py-3 text-left">SKU</th>
                            <th className="px-4 py-3 text-left">{t('common.fields.price')}</th>
                            <th className="px-4 py-3 text-left">{t('common.fields.stock')}</th>
                            <th className="px-4 py-3 text-center"></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-border-color">
                        {variants.map((variant, idx) => (
                            <tr key={idx} className="hover:bg-slate-50/50 dark:hover:bg-slate-900/20 transition-colors">
                                <td className="px-4 py-3">
                                    <div className="flex flex-wrap gap-1">
                                        {Object.entries(typeof variant.attributes === 'string' ? JSON.parse(variant.attributes) : variant.attributes).map(([k, v]) => (
                                            <Badge key={k} variant="outline" className="text-[10px] lowercase py-0">{k}: {v as string}</Badge>
                                        ))}
                                    </div>
                                </td>
                                <td className="px-4 py-3">
                                    <Input 
                                        className="h-8 text-xs w-full" 
                                        value={variant.sku} 
                                        onChange={(e) => updateVariant(idx, 'sku', e.target.value)}
                                    />
                                </td>
                                <td className="px-4 py-3">
                                    <Input 
                                        type="number"
                                        className="h-8 text-xs w-32" 
                                        value={variant.price} 
                                        onChange={(e) => updateVariant(idx, 'price', Number(e.target.value))}
                                    />
                                </td>
                                <td className="px-4 py-3">
                                    <Input 
                                        type="number"
                                        className="h-8 text-xs w-24" 
                                        value={variant.stockQuantity} 
                                        onChange={(e) => updateVariant(idx, 'stockQuantity', Number(e.target.value))}
                                    />
                                </td>
                                <td className="px-4 py-3 text-center">
                                    <button type="button" onClick={() => {
                                        const newVariants = variants.filter((_, i) => i !== idx);
                                        setVariants(newVariants);
                                        onChange(newVariants);
                                    }} className="text-slate-400 hover:text-red-500">
                                        <Trash2 size={16} />
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
      )}
    </div>
  );
};

import { render, screen, within } from '@testing-library/react';
import { describe, it, expect, vi } from 'vitest';
import { ProductUnitsManager, ProductUnitDto } from '../ProductUnitsManager';
import userEvent from '@testing-library/user-event';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';

// Mock dependencies
vi.mock('react-i18next', () => ({
  useTranslation: () => ({
    t: (key: string, options?: any) => {
        if (key === 'messages.confirmDelete') return `Are you sure you want to delete ${options.name}?`;
        return key;
    },
  }),
}));

// Mock ConfirmDialog and Badge to simplify testing
vi.mock('@/components/ui', async (importOriginal) => {
    const actual = await importOriginal<any>();
    return {
        ...actual,
        ConfirmDialog: ({ isOpen, onConfirm, message }: any) => {
            if (!isOpen) return null;
            return (
                <div data-testid="confirm-dialog">
                    <span>{message}</span>
                    <button onClick={onConfirm}>ConfirmDelete</button>
                </div>
            );
        },
        Badge: ({ children }: any) => <div data-testid="mock-badge">{children}</div>
    };
});

describe('ProductUnitsManager Component', () => {

    const baseProps = {
        baseUnitName: 'Cái',
        baseUnitPrice: 100000,
        onChange: vi.fn(),
        fetchUnitOptions: vi.fn().mockResolvedValue({ items: [], totalItems: 0 }),
        units: [] as ProductUnitDto[]
    };

    const renderWithProvider = (props = baseProps) => {
        const queryClient = new QueryClient({
            defaultOptions: {
                queries: { retry: false },
            },
        });
        return render(
            <QueryClientProvider client={queryClient}>
                <ProductUnitsManager {...props} />
            </QueryClientProvider>
        );
    };

    it('renders base unit correctly', () => {
        renderWithProvider();
        
        const elements = screen.getAllByText('Cái');
        expect(elements.length).toBeGreaterThan(0);
        expect(elements[0]).toBeInTheDocument();
        // Check for mock badge
        expect(screen.getByTestId('mock-badge')).toBeInTheDocument();
        expect(screen.getByText('product.defaultUnit')).toBeInTheDocument();
        // Use regex to match price regardless of locale separator
        expect(screen.getByText(/100[.,]000/)).toBeInTheDocument(); 
    });

    it('renders additional units', async () => {
        const units: ProductUnitDto[] = [
            { code: 'U1', unitName: 'Hộp', conversionRate: 10, price: 950000, isActive: true, isBaseUnit: false }
        ];
        renderWithProvider({ ...baseProps, units });
        
        // Use getAllByText if multiples expected, or better yet, be specific
        const unitRows = screen.getAllByTestId(/unit-row-/);
        expect(unitRows).toHaveLength(1);
        
        expect(within(unitRows[0]).getByText(/Hộp/i)).toBeInTheDocument();
        expect(within(unitRows[0]).getByDisplayValue('10')).toBeInTheDocument();
        expect(within(unitRows[0]).getByText(new RegExp(`× ${baseProps.baseUnitName}`, 'i'))).toBeInTheDocument();
        expect(within(unitRows[0]).getByDisplayValue('950.000')).toBeInTheDocument();
    });

    it('calls onChange when add button is clicked', async () => {
        renderWithProvider();
        
        const addButton = screen.getByText(/admin\.actions\.addUnit/i);
        await userEvent.click(addButton);
        
        expect(baseProps.onChange).toHaveBeenCalled();
    });

    it('calls onChange when delete is clicked', async () => {
        const units: ProductUnitDto[] = [
            { code: 'U1', unitName: 'Hộp', conversionRate: 10, price: 950000, isActive: true, isBaseUnit: false }
        ];
        renderWithProvider({ ...baseProps, units });
        
        // Find delete button by testid
        const deleteButton = screen.getByTestId('delete-unit-button-0');
        await userEvent.click(deleteButton); 
        
        // Check for mocked dialog
        const dialog = await screen.findByTestId('confirm-dialog');
        expect(dialog).toBeInTheDocument();
        expect(within(dialog).getByText(/Hộp/i)).toBeInTheDocument();
        
        const confirmBtn = screen.getByText('ConfirmDelete');
        await userEvent.click(confirmBtn);
        
        expect(baseProps.onChange).toHaveBeenCalled();
    });
});

import { memo, useState, useRef, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Search,
  ShoppingCart,
  Heart,
  User,
  Menu,
  X,
  Sun,
  Moon,
  ChevronDown,
  Phone,
  MessageCircle,
  Scale,
  Globe,
  Bell,
  LayoutDashboard,
  Package,
  LogOut,
} from 'lucide-react';
import { cn } from '@/utils/cn';
import { Button, ConfirmDialog } from '@/components/ui';
import { useCartStore, useWishlistStore, useUIStore, useCompareStore, useAuthStore, useNotificationStore, useToast } from '@/store';
import { type SignalRNotification } from '@/services/signalrService';
import { useClickOutside, useSignalR } from '@/hooks';
import { useCategories } from '@/hooks/useProducts';

export const Header = memo(() => {
  const { t, i18n } = useTranslation();
  const location = useLocation();
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [showCategories, setShowCategories] = useState(false);
  
  const { data: categories = [], isLoading: isLoadingCategories } = useCategories({ 
    enabled: showCategories || mobileMenuOpen 
  });
  const [showUserMenu, setShowUserMenu] = useState(false);
  const [showLangMenu, setShowLangMenu] = useState(false);
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);

  const handleLogoutClick = () => {
    setShowUserMenu(false);
    setMobileMenuOpen(false);
    setShowLogoutConfirm(true);
  };

  const navigate = useNavigate();
  const confirmLogout = () => {
    logout();
    setShowLogoutConfirm(false);
    navigate('/');
  };


  const categoriesRef = useClickOutside<HTMLDivElement>(() => setShowCategories(false));
  const userMenuRef = useClickOutside<HTMLDivElement>(() => setShowUserMenu(false));
  // const langMenuRef = useClickOutside<HTMLDivElement>(() => setShowLangMenu(false)); // Temporarily removed
  const langMenuRef = useRef<HTMLDivElement>(null); // Use simple ref for button
  const langDropdownRef = useRef<HTMLDivElement>(null); // Ref for dropdown portal

  const cartCount = useCartStore((state) => state.getItemCount());
  const wishlistCount = useWishlistStore((state) => state.items.length);
  const compareCount = useCompareStore((state) => state.items.length);
  const { theme, toggleTheme, setCartOpen } = useUIStore();
  const { user, isAuthenticated, logout } = useAuthStore();
  const { unreadCount, notifications, addNotification, markAllRead } = useNotificationStore();
  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useClickOutside<HTMLDivElement>(() => setShowNotifications(false));

  const { info } = useToast();

  const { on, isConnected } = useSignalR();

  useEffect(() => {
    if (!isConnected) return;

    const unsubscribeOrder = on('ReceiveOrderNotification', (data: string | SignalRNotification) => {
        const msg = typeof data === 'string' ? data : (data as SignalRNotification).Message || '';
        addNotification(msg);
        info(`${t('common.newOrder')}: ${msg}`);
    });
    
    const unsubscribeQuote = on('ReceiveQuoteNotification', (data: string | unknown) => {
         const msg = typeof data === 'string' ? data : (data as Record<string, any>).Message || '';
         addNotification(msg);
         info(`${t('common.newQuote') || 'New Quote'}: ${msg}`);
    });

    return () => {
        unsubscribeOrder();
        unsubscribeQuote();
    };
  }, [isConnected, on, addNotification, info, t]);

  // Manual click outside handler for language menu
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as Node;
      // Check if click is outside both the button and the dropdown
      const isOutsideButton = langMenuRef.current && !langMenuRef.current.contains(target);
      const isOutsideDropdown = langDropdownRef.current && !langDropdownRef.current.contains(target);

      if (isOutsideButton && isOutsideDropdown) {
        setShowLangMenu(false);
      }
    };
    if (showLangMenu) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [showLangMenu]);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      window.location.href = `/search?search=${encodeURIComponent(searchQuery)}`;
    }
  };

  const changeLanguage = (lang: string) => {
    i18n.changeLanguage(lang);
    localStorage.setItem('language', lang);
    setShowLangMenu(false);
  };

  return (
    <>
      <header className="bg-primary transition-colors duration-200 relative z-[101]">
      {/* Top Bar */}
      <div className="bg-gradient-to-r from-slate-900 to-slate-800 text-slate-300 text-xs py-2">
        <div className="container mx-auto px-4 flex justify-between items-center">
          <div className="flex gap-6">
            <a href="tel:1900123456" className="flex items-center gap-1 hover:text-white transition-colors">
              <Phone size={12} />
              <span>{t('shared.hotlineFull')}</span>
            </a>
            <a href="https://zalo.me" className="flex items-center gap-1 text-blue-400 hover:text-blue-300 transition-colors">
              <MessageCircle size={12} />
              <span>{t('shared.chatZalo')}</span>
            </a>
          </div>
          <div className="hidden md:flex gap-4">
            <Link to="/tracking" className="hover:text-white transition-colors">{t('header.trackOrder')}</Link>
            <Link to="/support" className="hover:text-white transition-colors">{t('header.support')}</Link>
            <Link to="/about" className="hover:text-white transition-colors">{t('header.about')}</Link>
          </div>
        </div>
      </div>

      {/* Main Header */}
      <div className="border-b py-3">
        <div className="container mx-auto px-4 flex items-center gap-6">
          {/* Logo */}
          <Link to="/" className="flex items-center gap-2 flex-shrink-0">
