              </div>
              <Button type="submit" rounded size="sm" className="px-6 h-9 shrink-0">
                {t('common.search')}
              </Button>
            </div>
          </form>

          {/* Actions */}
          <div className="flex items-center gap-1">
            {/* Language Switcher */}
            {/* Language Switcher */}
            <div className="relative" ref={langMenuRef}>
              <Button
                variant="ghost"
                size="sm"
                data-testid="lang-toggle"
                onClick={(e) => {
