                        ? 'bg-indigo-100 dark:bg-indigo-900/50 text-indigo-700 dark:text-indigo-300'
                        : 'hover:bg-gray-100 dark:hover:bg-slate-700 text-gray-700 dark:text-gray-200'
                    )}
                  >
                    <span className="text-xs font-semibold uppercase text-tertiary">VN</span> Tiếng Việt
                  </button>
                  <button
                    onClick={() => changeLanguage('en')}
                    className={cn(
                      'flex items-center gap-2 w-full px-3 py-2 text-sm rounded-md transition-colors',
                      (i18n.language || 'en').startsWith('en')
                        ? 'bg-indigo-100 dark:bg-indigo-900/50 text-indigo-700 dark:text-indigo-300'
                        : 'hover:bg-gray-100 dark:hover:bg-slate-700 text-gray-700 dark:text-gray-200'
                    )}
                  >
                    <span className="text-xs font-semibold uppercase text-tertiary">US</span> English
                  </button>
                </div>
              )}
            </div>

            {/* Notifications - Only for Admin or Logged in? For now everyone or Admin */}
            {user?.role === 'Admin' && (
                <div className="relative" ref={notificationRef}>
                    <Button variant="ghost" size="sm" className="relative" onClick={() => { setShowNotifications(!showNotifications); markAllRead(); }}>
                        <Bell size={20} />
                        {unreadCount > 0 && (
                            <span className="absolute -top-1 -right-1 w-4 h-4 bg-red-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center animate-pulse">
                                {unreadCount}
