import { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import { debounce, throttle } from 'lodash-es';

// Re-export product hooks
export {
    useProducts,
    useProduct,
    useCreateProduct,
    useUpdateProduct,
    useDeleteProduct,
    useCategories,
    useCategoriesList,
    productKeys,
} from './useProducts';

export { useSuppliers, useSuppliersPaged } from './useSuppliers';
export { useUnits } from './useUnits';
export { useBrands } from './useBrands';

// Re-export order hooks
export { useOrders, useAdminOrders, useUpdateOrderStatus, useOrder } from './useOrders';

export * from './useEntityManager';
export * from './usePagination';
export * from './useRoles';
export { useDataTable } from './useDataTable';
export { useSignalR } from './useSignalR';

/**
 * Hook for debounced value
 * @param value - Value to debounce
 * @param delay - Debounce delay in ms
 */
export function useDebounce<T>(value: T, delay: number = 300): T {
    const [debouncedValue, setDebouncedValue] = useState<T>(value);

    useEffect(() => {
        const timer = setTimeout(() => setDebouncedValue(value), delay);
        return () => clearTimeout(timer);
    }, [value, delay]);

    return debouncedValue;
}

/**
 * Hook for debounced callback
 * @param callback - Callback to debounce
 * @param delay - Debounce delay in ms
 */
export function useDebouncedCallback<T extends (...args: unknown[]) => unknown>(
    callback: T,
    delay: number = 300
): T {
    const callbackRef = useRef(callback);

    useEffect(() => {
        callbackRef.current = callback;
    });

    const debouncedFn = useMemo(
        () => debounce((...args: Parameters<T>) => callbackRef.current(...args), delay),
        [delay]
    );

    useEffect(() => {
        return () => {
            debouncedFn.cancel();
        };
    }, [debouncedFn]);

    return debouncedFn as unknown as T;
}

/**
 * Hook for throttled callback
 * @param callback - Callback to throttle
 * @param delay - Throttle delay in ms
 */
export function useThrottledCallback<T extends (...args: unknown[]) => unknown>(
    callback: T,
    delay: number = 300
): T {
    const callbackRef = useRef(callback);

    useEffect(() => {
        callbackRef.current = callback;
    });

    const throttledFn = useMemo(
        () => throttle((...args: Parameters<T>) => callbackRef.current(...args), delay),
        [delay]
    );

    useEffect(() => {
        return () => {
            throttledFn.cancel();
        };
    }, [throttledFn]);

    return throttledFn as unknown as T;
}

/**
 * Hook for local storage state
 * @param key - Storage key
 * @param initialValue - Initial value
 */
export function useLocalStorage<T>(
    key: string,
    initialValue: T
): [T, (value: T | ((prev: T) => T)) => void, () => void] {
    const [storedValue, setStoredValue] = useState<T>(() => {
        try {
            const item = window.localStorage.getItem(key);
            return item ? JSON.parse(item) : initialValue;
        } catch {
            return initialValue;
        }
    });

    const setValue = useCallback(
        (value: T | ((prev: T) => T)) => {
            try {
                const valueToStore = value instanceof Function ? value(storedValue) : value;
                setStoredValue(valueToStore);
                window.localStorage.setItem(key, JSON.stringify(valueToStore));
            } catch (error) {
                console.error('Error saving to localStorage:', error);
            }
        },
        [key, storedValue]
    );

    const removeValue = useCallback(() => {
        try {
            window.localStorage.removeItem(key);
            setStoredValue(initialValue);
        } catch (error) {
            console.error('Error removing from localStorage:', error);
        }
    }, [key, initialValue]);

    return [storedValue, setValue, removeValue];
}

/**
 * Hook for click outside detection
 * @param handler - Handler to call when clicked outside
 */
export function useClickOutside<T extends HTMLElement>(
    handler: () => void
): React.RefObject<T | null> {
    const ref = useRef<T>(null);

    useEffect(() => {
        const listener = (event: MouseEvent | TouchEvent) => {
            if (!ref.current || ref.current.contains(event.target as Node)) {
                return;
            }
            handler();
        };

        document.addEventListener('mousedown', listener);
        document.addEventListener('touchstart', listener);

        return () => {
            document.removeEventListener('mousedown', listener);
            document.removeEventListener('touchstart', listener);
        };
    }, [handler]);

    return ref;
}

/**
 * Hook for window size
 */
export function useWindowSize() {
    const [size, setSize] = useState({
        width: typeof window !== 'undefined' ? window.innerWidth : 0,
        height: typeof window !== 'undefined' ? window.innerHeight : 0,
    });

    const handleResize = useThrottledCallback(() => {
        setSize({
            width: window.innerWidth,
            height: window.innerHeight,
        });
    }, 200);

    useEffect(() => {
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, [handleResize]);

    return size;
}

/**
 * Hook for intersection observer (lazy loading)
 */
export function useIntersectionObserver(
    options?: IntersectionObserverInit
): [React.RefObject<HTMLDivElement | null>, boolean] {
    const ref = useRef<HTMLDivElement>(null);
    const [isIntersecting, setIsIntersecting] = useState(false);

    useEffect(() => {
        const observer = new IntersectionObserver(([entry]) => {
            setIsIntersecting(entry.isIntersecting);
        }, options);

        if (ref.current) {
            observer.observe(ref.current);
        }

        return () => observer.disconnect();
    }, [options]);

    return [ref, isIntersecting];
}

/**
 * Hook for previous value
 */
export function usePrevious<T>(value: T): T | undefined {
    const ref = useRef<T | undefined>(undefined);

    useEffect(() => {
        ref.current = value;
    }, [value]);

    // eslint-disable-next-line react-hooks/exhaustive-deps
    return useMemo(() => ref.current, [value]);
}

import { useEffect, useRef, RefObject } from 'react';

type Handler = (event: MouseEvent | TouchEvent) => void;

export const useClickOutside = <T extends HTMLElement = HTMLElement>(
    handler: Handler
): RefObject<T> => {
    const ref = useRef<T>(null);

    useEffect(() => {
        const listener = (event: MouseEvent | TouchEvent) => {
            const el = ref?.current;

            // Do nothing if clicking ref's element or descendent elements
            if (!el || el.contains(event.target as Node)) {
                return;
            }

            handler(event);
        };

        document.addEventListener('mousedown', listener);
        document.addEventListener('touchstart', listener);

        return () => {
            document.removeEventListener('mousedown', listener);
            document.removeEventListener('touchstart', listener);
        };
    }, [ref, handler]);

    return ref as any;
};

import { useState, useMemo } from 'react';
import { applyClientFilters } from '@/utils/queryHelper';
import { SearchCondition } from '@/services/api';

interface UseDataTableProps<T> {
    data: T[];
    filterFn?: (item: T, filterTerm: string, filterField?: string) => boolean;
    initialSort?: { field: keyof T; direction: 'asc' | 'desc' };
}

export const useDataTable = <T extends { id: string | number } & Record<string, any>>({
    data,
    filterFn,
    initialSort,
}: UseDataTableProps<T>) => {
    // Selection
    const [selectedIds, setSelectedIds] = useState<Set<string | number>>(new Set());

    // Search & Filter
    const [searchQuery, setSearchQuery] = useState('');
    const [searchField, setSearchField] = useState<string>('all');

    // Sort
    const [sortConfig, setSortConfig] = useState<{ field: keyof T; direction: 'asc' | 'desc' } | null>(
        initialSort || null
    );

    // Pagination
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);

    // --- Logic ---

    // 1. Filter
    const filteredData = useMemo(() => {
        let result = data;

        // Apply external filters (complex SearchDTOs) logic locally if data is all here
        // Note: If server-side pagination is used, 'data' is usually just current page, so this runs on that subset.
        // But for client-side tables, this is powerful.
        // We can extend this hook to accept 'filters' prop if needed, 
        // but for now let's keep searchField/searchQuery behavior and map it to a SearchDTO.

        if (searchQuery) {
            const lowerQuery = searchQuery.toLowerCase();
            // Reuse the simple logic OR use the new helper?
            // Let's use the new helper for single field search to ensure consistency
            if (searchField !== 'all') {
                result = applyClientFilters(result, [{
                    searchField: searchField,
                    searchCondition: SearchCondition.Contains,
                    searchValue: lowerQuery
                }]);
            } else {
                // Fallback to "All Fields" search which is not in SearchDTO standard usually
                result = result.filter(item =>
                    Object.values(item).some(val =>
                        String(val).toLowerCase().includes(lowerQuery)
                    )
                );
            }
        }

        if (filterFn) {
            result = result.filter(item => filterFn(item, searchQuery.toLowerCase(), searchField));
        }

        return result;
    }, [data, searchQuery, searchField, filterFn]);

    // 2. Sort
    const sortedData = useMemo(() => {
        if (!sortConfig) return filteredData;

        return [...filteredData].sort((a, b) => {
            const aVal = a[sortConfig.field];
            const bVal = b[sortConfig.field];

            if (aVal < bVal) return sortConfig.direction === 'asc' ? -1 : 1;
            if (aVal > bVal) return sortConfig.direction === 'asc' ? 1 : -1;
            return 0;
        });
    }, [filteredData, sortConfig]);

    // 3. Paginate
    const paginatedData = useMemo(() => {
        const startIndex = (currentPage - 1) * itemsPerPage;
        return sortedData.slice(startIndex, startIndex + itemsPerPage);
    }, [sortedData, currentPage, itemsPerPage]);

    const totalPages = Math.ceil(filteredData.length / itemsPerPage);

    // Handlers
    const handleSelectAll = (checked: boolean) => {
        if (checked) {
            // Select all visible items (or all filtered items depending on UX preference)
            // Usually users expect "Select All" to select current page or all 
            // Let's implement select all filtered for power usage
            setSelectedIds(new Set(filteredData.map(d => d.id)));
        } else {
            setSelectedIds(new Set());
        }
    };

    const handleSelectRow = (id: string | number) => {
        setSelectedIds((prev) => {
            const next = new Set(prev);
            if (next.has(id)) {
                next.delete(id);
            } else {
                next.add(id);
            }
            return next;
        });
    };

    const handleSort = (field: keyof T) => {
        setSortConfig((current) => {
            if (current?.field === field) {
                return { field, direction: current.direction === 'asc' ? 'desc' : 'asc' };
            }
            return { field, direction: 'asc' };
        });
    };

    return {
        // State
        selectedIds,
        searchQuery,
        searchField,
        sortConfig,
        currentPage,
        itemsPerPage,

        // Data
        data: paginatedData,
        totalItems: filteredData.length,
        totalPages,

        // Setters
        setSearchQuery,
        setSearchField,
        setItemsPerPage,
        setCurrentPage,

        // Actions
        handleSelectAll,
        handleSelectRow,
        handleSort,
        resetSelection: () => setSelectedIds(new Set()),
    };
};

