    const { t } = useTranslation();
    const queryClient = useQueryClient();
    const toast = useToast();

    const [isFormOpen, setIsFormOpen] = useState(false);
    const [editingItem, setEditingItem] = useState<T | null>(null);
    const [itemToDelete, setItemToDelete] = useState<T | null>(null);
    const [isFetchingDetail, setIsFetchingDetail] = useState(false);

    const createMutation = useMutation({
        mutationFn: (data: CreateDto) => service.create(data),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey });
            toast.success(translations?.createSuccess || t('common.createSuccess'));
            setIsFormOpen(false);
        },
        onError: (error: Error) => {
            toast.error(error?.message || translations?.createError || t('common.createError'));
        },
    });

    const updateMutation = useMutation({
        mutationFn: ({ id, data }: { id: string | number; data: UpdateDto }) => service.update(id, data),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey });
            toast.success(translations?.updateSuccess || t('common.updateSuccess'));
            setIsFormOpen(false);
            setEditingItem(null);
        },
        onError: (error: Error) => {
            toast.error(error?.message || translations?.updateError || t('common.updateError'));
        },
    });

    const deleteMutation = useMutation({
        mutationFn: (id: string | number) => service.delete(id),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey });
            toast.success(translations?.deleteSuccess || t('common.deleteSuccess'));
            setItemToDelete(null);
        },
        onError: (error: Error) => {
            toast.error(error?.message || translations?.deleteError || t('common.deleteError'));
        },
    });

    const openCreate = useCallback(() => {
        setEditingItem(null);
        setIsFormOpen(true);
    }, []);

    const openEdit = useCallback(async (item: T) => {
        setEditingItem(item);
        setIsFormOpen(true);

        // Try to fetch fresh details if service supports it
        const id = item.code;
        if (service.getByCode && id) {
            setIsFetchingDetail(true);
            try {
                const response = await service.getByCode(id, includeChildrenOnEdit ? { includeChildren: true } : undefined);
                // Check if response wraps data in ApiResponse logic (success/data props)
                if (response && response.success && response.data) {
                    setEditingItem(response.data);
                } else if (response) {
                    // Fallback if response is direct object or different format
                    setEditingItem(response as T);
                }
            } catch (err) {
                console.error("Failed to fetch fresh item details", err);
                // Optionally toast warning?
            } finally {
                setIsFetchingDetail(false);
            }
        }
    }, [service, includeChildrenOnEdit]);

    const closeForm = useCallback(() => {
        setIsFormOpen(false);
        setEditingItem(null);
    }, []);

    const confirmDelete = useCallback((item: T) => {
        setItemToDelete(item);
    }, []);

    const cancelDelete = useCallback(() => {
        setItemToDelete(null);
    }, []);

    const processCreate = useCallback((data: CreateDto) => {
        createMutation.mutate(data);
    }, [createMutation]);

    const processUpdate = useCallback((id: any, data: UpdateDto) => {
        updateMutation.mutate({ id, data });
    }, [updateMutation]);

    const processDelete = useCallback((id: any) => {
        deleteMutation.mutate(id);
    }, [deleteMutation]);

    return {
        // State
        isFormOpen,
        editingItem,
        itemToDelete,
        isFetchingDetail,

        // Actions
        openCreate,
        openEdit,
        closeForm,
        confirmDelete,
        cancelDelete,

        // Processors
        create: processCreate,
        update: processUpdate,
        delete: processDelete,

        // Mutations (full objects if needed)
        createMutation,
        updateMutation,
        deleteMutation,

        // Loading states
        isLoading: createMutation.isPending || updateMutation.isPending || deleteMutation.isPending,
        isCreating: createMutation.isPending,
        isUpdating: updateMutation.isPending,
        isDeleting: deleteMutation.isPending,
    };
};

import { useState, useCallback } from 'react';
import { exportToExcel, ExportColumn } from '@/utils/export';

interface UseExportOptions<T> {
    defaultFilename?: string;
    defaultColumns?: ExportColumn<T>[];
}

export function useExport<T extends Record<string, any>>(initialOptions: UseExportOptions<T> = {}) {
    const [isExporting, setIsExporting] = useState(false);

    const exportData = useCallback(async (
        data: T[] | Promise<T[]>,
        filename: string = initialOptions.defaultFilename || 'export',
        columns?: ExportColumn<T>[]
    ) => {
        setIsExporting(true);
        try {
            const resolvedData = await Promise.resolve(data);
            const cols = columns || initialOptions.defaultColumns;
            await exportToExcel(resolvedData, filename, cols);
        } catch (error) {
            console.error('Export failed:', error);
            throw error;
        } finally {
            setIsExporting(false);
        }
    }, [initialOptions.defaultFilename, initialOptions.defaultColumns]);

    return { isExporting, exportData };
}

/**
 * useOrders hook - React Query hooks for Order operations
 */
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { orderService, type UpdateOrderRequest } from '@/services/orderService';
import { SearchCondition } from '@/services/baseService';

export function useOrders(params?: {
    pageIndex?: number;
    pageSize?: number;
    status?: string;
}) {
    return useQuery({
        queryKey: ['orders', params],
        queryFn: () => orderService.search({
            pageIndex: params?.pageIndex || 1,
            pageSize: params?.pageSize || 10,
            search: params?.status,
            searchField: params?.status ? 'status' : undefined
        }),
        select: (response) => {
            const pageSize = params?.pageSize || 10;
            const pageIndex = params?.pageIndex || 1;
            const totalItems = response.data?.totalItems || 0;
            const totalPages = Math.ceil(totalItems / pageSize);

            // Deduplicate
            const uniqueItems = Array.from(new Map((response.data?.items || []).map(item => [item.code, item])).values());

            return {
                orders: uniqueItems,
                totalPages,
                totalItems,
                pageNumber: pageIndex
            };
        }
    });
}

export function useAdminOrders(params?: {
    pageIndex?: number;
    pageSize?: number;
    filters?: Record<string, any>;
}) {
    const searchFilters: { field: string; value: string; operator?: SearchCondition }[] = [];
    const searchTerm = params?.filters?.search;

    // Convert filters to array for backend
    if (params?.filters) {
        Object.entries(params.filters).forEach(([key, value]) => {
            if (value && key !== 'search') {
                searchFilters.push({ field: key, value: String(value) });
            }
        });
    }

    return useQuery({
        queryKey: ['admin-orders', params],
        queryFn: () => orderService.search({
            pageIndex: params?.pageIndex || 1,
            pageSize: params?.pageSize || 10,
            search: searchTerm,
            searchField: 'all', // Backend will search across default fields if not specified
            filters: searchFilters.length > 0 ? searchFilters : undefined
        }),
        select: (response) => {
            const pageSize = params?.pageSize || 10;
            const pageIndex = params?.pageIndex || 1;
            const totalItems = response.data?.totalItems || 0;
            const totalPages = Math.ceil(totalItems / pageSize);

            // Deduplicate
            const uniqueItems = Array.from(new Map((response.data?.items || []).map(item => [item.code, item])).values());

            return {
                orders: uniqueItems,
                totalPages,
                totalItems,
                pageNumber: pageIndex
            };
        }
    });
}

export function useUpdateOrderStatus() {
    const queryClient = useQueryClient();

    return useMutation({
        mutationFn: ({ code, status }: { code: string; status: string }) =>
            orderService.update(code, { status }),
