                    ) : (
                      <Link to={`/quote-request/${product.code}`}>
                        <Button size="sm" variant="outline">
                          {t('product.requestQuote')}
                        </Button>
                      </Link>
                    )}
                  </td>
                ))}
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

