import { useState, useEffect } from 'react';

import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { motion } from 'framer-motion';
import {
  ChevronRight,
  ArrowRight,
  Sparkles,
  Zap,
  Gift,
  TrendingUp,
  Loader2,
} from 'lucide-react';
import { ProductCard } from '@/components/common/ProductCard';
import SharedImage from '@/components/common/Image';
import { Button } from '@/components/ui';
import { useProducts, useCategories } from '@/hooks/useProducts';
import { useQuery } from '@tanstack/react-query';
import { promotionService, type Promotion } from '@/services/promotionService';

import { HOME_BANNERS, FLASH_SALE_TIMES } from '@/data/homeData';
import { formatCurrency } from '@/utils/format';
import { useBrands } from '@/hooks/useBrands';


// ============ Component ============



import { SectionHeader } from '@/components/common/SectionHeader';

// ============ Component ============

// ============ Home Page Component ============
export const HomePage = () => {
  const { t } = useTranslation();
  const [currentSlide, setCurrentSlide] = useState(0);

  // Fetch products from API
  const { data: productsData, isLoading } = useProducts({
    pageIndex: 1,
    pageSize: 20,
  });

  // Fetch categories from API
  const { data: categories = [], isLoading: loadingCategories } = useCategories();


  const { data: brandsData, isLoading: isLoadingBrands } = useBrands();
  const brandPartners = brandsData?.data?.items || [];

  const products = productsData?.products || [];

  const featuredProducts = products.slice(0, 8);
  const newProducts = products.slice(0, 4);
  // Fetch flash sales
  const { data: flashSales } = useQuery({
    queryKey: ['flash-sales'],
    queryFn: () => promotionService.getFlashSales(),
  });

  const flashSaleProductCodes = flashSales?.data?.flatMap((p: Promotion) => p.productCodes || []) || [];
  
  // Fetch flash sale products
  const { data: flashSaleProductsData } = useProducts({
      pageIndex: 1,
      pageSize: 20,
      ids: flashSaleProductCodes,
      enabled: flashSaleProductCodes.length > 0
  });

  const saleProducts = flashSaleProductsData?.products || [];

  // Countdown Timer Logic
  const [timeLeft, setTimeLeft] = useState<{hours: number, minutes: number, seconds: number}>({ hours: 0, minutes: 0, seconds: 0 });

  useEffect(() => {
    if (!flashSales?.data || flashSales.data.length === 0) return;
    
    // Find the soonest ending flash sale
    const activeFlashSale = flashSales.data?.find((p: Promotion) => p.isActive && new Date(p.endDate) > new Date());
    if(!activeFlashSale) return;

    const targetDate = new Date(activeFlashSale.endDate).getTime();

    const timer = setInterval(() => {
      const now = new Date().getTime();
      const distance = targetDate - now;

      if (distance < 0) {
        clearInterval(timer);
        return;
      }

      setTimeLeft({
        hours: Math.floor((distance / (1000 * 60 * 60))), // Total hours left
        minutes: Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60)),
        seconds: Math.floor((distance % (1000 * 60)) / 1000)
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [flashSales?.data]);

  // Auto slide
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % HOME_BANNERS.length);
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="min-h-screen">
      {/* Hero Banner Slider */}
      <section className="relative h-[400px] md:h-[500px] lg:h-[600px] overflow-hidden">
        {HOME_BANNERS.map((banner, index) => (

          <motion.div
            key={banner.id}
            className={`absolute inset-0 ${index === currentSlide ? 'z-10' : 'z-0'}`}
            initial={{ opacity: 0 }}
            animate={{ opacity: index === currentSlide ? 1 : 0 }}
            transition={{ duration: 0.5 }}
          >
            {/* Background */}
            <div
              className="absolute inset-0 bg-cover bg-center"
              style={{ backgroundImage: `url(${banner.image})` }}
            />
            <div className="absolute inset-0 bg-gradient-to-r from-black/70 via-black/40 to-transparent" />

            {/* Content */}
            <div className="container mx-auto px-4 h-full flex items-center relative z-10">
              <div className="max-w-xl text-white">
                <motion.span
                  className="inline-flex items-center gap-2 px-4 py-2 bg-white/20 backdrop-blur-sm rounded-full text-sm font-semibold mb-4"
                  initial={{ y: 20, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  transition={{ delay: 0.2 }}
                >
                  <Sparkles size={16} />
                  {t(`home.banners.${banner.id}.subtitle`)}
                </motion.span>

                <motion.h1
                  className="text-3xl md:text-4xl lg:text-5xl font-extrabold mb-4"
                  initial={{ y: 30, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  transition={{ delay: 0.3 }}
                >
                  {t(`home.banners.${banner.id}.title`)}
                </motion.h1>

                <motion.p
                  className="text-lg md:text-xl opacity-90 mb-6"
                  initial={{ y: 30, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  transition={{ delay: 0.4 }}
                >
                  {t(`home.banners.${banner.id}.description`)}
                </motion.p>

                <motion.div
                  initial={{ y: 30, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  transition={{ delay: 0.5 }}
                >
                  <Link to={banner.link}>
                    <Button size="lg" rounded rightIcon={<ArrowRight size={20} />}>
                      {t(`home.banners.${banner.id}.cta`)}
                    </Button>
                  </Link>
                </motion.div>
              </div>
            </div>
          </motion.div>
        ))}

        {/* Dots */}
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex gap-2 z-20">
          {HOME_BANNERS.map((_, index) => (

            <button
              key={index}
              className={`w-3 h-3 rounded-full border-2 border-white transition-all ${index === currentSlide ? 'bg-white scale-110' : 'bg-transparent'
                }`}
              onClick={() => setCurrentSlide(index)}
            />
          ))}
        </div>
      </section>

      {/* Categories */}
      <section className="py-12 bg-secondary">
        <div className="container mx-auto px-4">
          <SectionHeader
            title={t('home.categories')}
            icon={<span className="text-2xl">🏷️</span>}
            viewAllLink="/products"

          />



          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
            {loadingCategories ? (
              Array.from({ length: 6 }).map((_, idx) => (
                <div key={idx} className="bg-primary rounded-xl p-4 flex flex-col items-center justify-center gap-3 animate-pulse">
                  <div className="w-24 h-24 bg-secondary/50 rounded-full" />
                  <div className="h-4 w-20 bg-secondary/50 rounded" />
                </div>
              ))
            ) : (
              categories.slice(0, 6).map((cat) => (
                <Link
                  key={cat.code}
                  to={`/products?category=${cat.code}`}
